import{_ as a,o as e,c as s,f as n}from"./app-55c326ac.js";const t={},r=n(`<h1 id="iptable-防火墙" tabindex="-1"><a class="header-anchor" href="#iptable-防火墙" aria-hidden="true">#</a> Iptable 防火墙</h1><h2 id="什么是防火墙" tabindex="-1"><a class="header-anchor" href="#什么是防火墙" aria-hidden="true">#</a> 什么是防火墙</h2><p>防火墙：就是用于实现linux下访问控制的功能的，分为硬件和软件防火墙。防火墙工作的地方一般是在网络的边缘。任务就是：定义防火墙的策略，规则，以达到让它对出入网路的IP，数据进行检测（防火墙怎样去工作）</p><p>3.4层的防火墙，叫网络层防火墙<br> 7层的防火墙，叫代理层的网关<br><strong>三层的防火墙</strong>(网络层的防火墙)会在这层==对<strong>源地址</strong>和<strong>目标地址</strong>进行检测==。 七层的防火墙，不管源端口，目标端口，源地址，目标地址，都会对所有的东西进行检查。<br> 就设计原理将，七层防火墙更加安全， 但却造成效率最低。一般的防火墙方案，都是两者结合。<br> 由于：都需要从防火墙所控制的这个口进行访问，所以防火墙的工作效率就成了用户能够访问数据多少的一个最重要的控制，不好的配置容易造成流量瓶颈。</p><h3 id="iptables的工作原理" tabindex="-1"><a class="header-anchor" href="#iptables的工作原理" aria-hidden="true">#</a> iptables的工作原理</h3><p>iptables的前身 ipfirewall iptables：能够将规则组成一个列表，实现绝对详细的访问控制功能</p><p>iptables是工作在用户控件中，定义规则的，定义的规则，可以让在内核空间当中的netfilter进行读取。而放入内核的地方必须要是特定的位置，必须是tcp/ip的协议栈经过的地方。<br> 这个地方叫：netfilter(网络过滤器)<br> 系统在内核空间中选择了5个位置：</p><ul><li>内核空间中：从一个网络接口进来，到另一个网络接口出去的</li><li>数据包从内核流入用户空间的</li><li>数据包从用户空间流出的</li><li>进入/离开本机的外网接口</li><li>进入/离开本机的内网接口</li></ul><hr><p>==<strong>iptables的工作机制</strong>== 当在做NAT和DNAT的时候，目标地址转换必须在路由之前转换。需要在外网后内网前进行设置关卡 五个位置，也成为了五个规则链（五链）</p><ul><li>PREROUTING （路由前）</li><li>INPUT （数据包流入口）</li><li>FORWARD （转发网卡）</li><li>OUTPUT （数据包出口）</li><li>POSTROUTING （路由后） 上面就是netfilter（网络过滤器）的五链，只要经过本机，必将经过这5个链中的其中一个链</li></ul><h2 id="四表" tabindex="-1"><a class="header-anchor" href="#四表" aria-hidden="true">#</a> 四表</h2><hr><p>==<strong>防火墙的策略</strong>==<br> 两种：“通”策略，“赌”策略。<br> 通策略，默认门是关着的，必须要定义谁能进。堵策略则是，大门是洞开的，但是你必须有身份认证，否则不能进。所以我们要定义，让进来的进来，让出去的出去，所以通，是要全通，而堵，则是要选择</p><hr><blockquote><p>四表：raw表，mangle表，nat表，filterbiao<br> 五链：PREROUTING，INPUT，FORWARD，OUTPUT，POSTROUTING。</p></blockquote><h3 id="规则表" tabindex="-1"><a class="header-anchor" href="#规则表" aria-hidden="true">#</a> 规则表</h3><table><thead><tr><th>表</th><th>链</th><th>作用</th></tr></thead><tbody><tr><td>filter</td><td>INPUT，FORWARD，OUTPUT</td><td>过滤数据包。内科模块：iptables_filter</td></tr><tr><td>Nat</td><td>PREROUTING，POSTROUTING，OUTPUT</td><td>用于网络地址转换(IP,端口)。内科模块：iptables_nat</td></tr><tr><td>Mangle</td><td>PREROUTING，INPUT，FORWARD，OUTPUT，POSTROUTING</td><td>修改数据包的服务类型，TTL，并且可以配置路由实现QOS。内核模块：iptables_mangle(<strong>这个表看着比较麻烦。但是设置策略时几乎都不会用到它</strong>)</td></tr><tr><td>Raw</td><td>OUOTPUT，PREROUTING</td><td>决定数据包是否被状态跟踪机制处理。内核模块：iptabls_raw</td></tr></tbody></table><h3 id="规则链" tabindex="-1"><a class="header-anchor" href="#规则链" aria-hidden="true">#</a> 规则链</h3><table><thead><tr><th>链</th><th>作用</th></tr></thead><tbody><tr><td>INPUT</td><td>进来的数据包应用此规则链中的策略</td></tr><tr><td>OUTPUT</td><td>外出的数据包应用此规则链中的策略</td></tr><tr><td>FORWARD</td><td>转发数据包时应用此规则链中的策略</td></tr><tr><td>PREROUTING</td><td>对数据包做路由选择前应用此链中的规则（<strong>所有的书记包进来的时候都会由这个链处理</strong>）</td></tr><tr><td>POSTROUTING</td><td>对数据包做路由选择后应用此链中的规则（<strong>所有的数据包出来的时候都会由这个链处理</strong>）</td></tr></tbody></table><h3 id="规则表之间的有限顺序" tabindex="-1"><a class="header-anchor" href="#规则表之间的有限顺序" aria-hidden="true">#</a> 规则表之间的有限顺序</h3><p>Raw-mangle-nat-filter<br> 规则链之间的优先顺序（三种情况）：</p><h4 id="第一种情况-入站数据流向" tabindex="-1"><a class="header-anchor" href="#第一种情况-入站数据流向" aria-hidden="true">#</a> 第一种情况：入站数据流向</h4><p>从外界到达防火墙的数据包，先被PREROUTING规则链处理(是否修改数据包地址等)，之后会进行路由选择(判断数据包应该发往何处)，如果数据包的目标主机是<strong>防火墙本机</strong>(比如说Internet用户访问防火墙主机中的web服务器的数据包)，那么内核将其传给INPUT链进行处理(决定是否允许通过等)，通过以后再交给系统上层的应用程序(比如apache服务器)进行响应</p><h4 id="第二种情况-转发数据流向" tabindex="-1"><a class="header-anchor" href="#第二种情况-转发数据流向" aria-hidden="true">#</a> 第二种情况：转发数据流向</h4><p>来自外界的数据包达到防火墙后，首先被PREROUTING规则链处理，之后会进行路由选择，如果数据包的目标地址是其他外部地址(比如局域网用户通过网关访问QQ站点的数据包)，则内核将其传递给FORWARD链进行处理(是否转发或拦截)，然后交给POSTROUTING规则链(是否修改数据包的地址等)进行处理。</p><h4 id="第三种情况-出站数据流向" tabindex="-1"><a class="header-anchor" href="#第三种情况-出站数据流向" aria-hidden="true">#</a> 第三种情况 出站数据流向</h4><p>防火墙本机向外部地址发送的数据包(比如在防火墙主机中测试公网DNS服务器时)，首先被OUTPUT规则链处理，之后进行路由选择，然后传递给POSTROUTING规则链(是否修改数据包的地址等)进行处理</p><h2 id="常用命令" tabindex="-1"><a class="header-anchor" href="#常用命令" aria-hidden="true">#</a> 常用命令</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 防止DDOS攻击脚本  </span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-i</span> eth0 <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">--syn</span> <span class="token parameter variable">-m</span> connlimit --connlimit-above <span class="token number">15</span> <span class="token parameter variable">-j</span> DROP
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">-m</span> state <span class="token parameter variable">--state</span> ESTABLISHED,RELATED <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 防止cc攻击</span>
<span class="token comment">## 1)控制单个IP的最大并发连接数</span>
iptables <span class="token parameter variable">-I</span> INPUT <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">--dport</span> <span class="token number">80</span> <span class="token parameter variable">-m</span> connlimit --connlimit-above <span class="token number">50</span> <span class="token parameter variable">-j</span> REJECT
<span class="token comment">## 2)控制单个IP的某段时间的连接数</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> icmp <span class="token parameter variable">-m</span> limit <span class="token parameter variable">--limit</span> <span class="token number">1</span>/m --limit-burst <span class="token number">10</span> <span class="token parameter variable">-j</span> REJECT
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> icmp <span class="token parameter variable">-J</span> DROP

<span class="token comment"># 拒绝所有的IP访问所有的端口</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-j</span> REJECT --reject-with icmp-port-unreachable

<span class="token comment"># 允许公司IP访问MySQL</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-s</span> <span class="token number">61.149</span>.47.34/32 <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">-m</span> tcp <span class="token parameter variable">--dport</span> <span class="token number">3306</span> <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 允许公司IP访问Redis</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-s</span> <span class="token number">61.149</span>.47.34/32 <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">-m</span> tcp <span class="token parameter variable">--dport</span> <span class="token number">6379</span> <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 允许所有IP访问网站</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">-m</span> tcp <span class="token parameter variable">--dport</span> <span class="token number">80</span> <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment">#允许服务器访问外网</span>
iptable <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-m</span> state <span class="token parameter variable">--state</span> RELATED,ESTABLISHED <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 允许本地回环</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-i</span> lo <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 允许ping请求</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> icmp <span class="token parameter variable">-m</span> icmp --icmp-type <span class="token number">8</span> <span class="token parameter variable">-j</span> ACCEPT

<span class="token comment"># 允许所有IP访问8081 10050 65008端口</span>
iptables <span class="token parameter variable">-A</span> INPUT <span class="token parameter variable">-p</span> tcp <span class="token parameter variable">-m</span> multiport <span class="token parameter variable">--dports</span> <span class="token number">8081,10050</span>,65008 <span class="token parameter variable">-j</span> ACCEPT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,30),p=[r];function l(i,c){return e(),s("div",null,p)}const b=a(t,[["render",l],["__file","IptableInfo.html.vue"]]);export{b as default};
